#!/usr/bin/env node
/**
 * bump-legacy-assets.js
 *
 * The 17 guide pages + 6 tool pages (search, map, compare, plan-my-trip,
 * find-my-coach, favorites) were chrome-wrapped via a Python migration
 * earlier and aren't regenerated by build-v2.js. So when ASSET_VERSION
 * bumps, those 23 pages get stranded at the old version.
 *
 * This script scans those 23 files and updates:
 *   - ?v=<old> -> ?v=<current> on stylesheet/script refs
 *   - Footer "v<old>" -> "v<current>" timestamp marker
 *
 * Run as: node scripts/bump-legacy-assets.js
 * Idempotent. Safe to run multiple times.
 */

const fs = require('fs');
const path = require('path');

// Read current asset version from build-v2.js
const buildSrc = fs.readFileSync(path.join(__dirname, '..', 'build-v2.js'), 'utf8');
const m = buildSrc.match(/const ASSET_VERSION\s*=\s*['"](\d+)['"]/);
if (!m) { console.error('Could not find ASSET_VERSION in build-v2.js'); process.exit(1); }
const CURRENT = m[1];

const ROOT = path.resolve(__dirname, '..');

// Legacy pages that don't go through build-v2.js
const LEGACY_PAGES = [];
const guidesDir = path.join(ROOT, 'guides');
if (fs.existsSync(guidesDir)) {
  for (const entry of fs.readdirSync(guidesDir, { withFileTypes: true })) {
    if (entry.isDirectory()) {
      const p = path.join(guidesDir, entry.name, 'index.html');
      if (fs.existsSync(p)) LEGACY_PAGES.push(p);
    }
  }
  const idx = path.join(guidesDir, 'index.html');
  if (fs.existsSync(idx)) LEGACY_PAGES.push(idx);
}
for (const slug of ['search', 'compare', 'map', 'plan-my-trip', 'find-my-coach', 'favorites', 'changelog']) {
  const p = path.join(ROOT, slug, 'index.html');
  if (fs.existsSync(p)) LEGACY_PAGES.push(p);
}
// Round 21 - hand-maintained root homepage also carries asset-version refs.
{
  const rootIndex = path.join(ROOT, 'index.html');
  if (fs.existsSync(rootIndex)) LEGACY_PAGES.push(rootIndex);
}

let bumped = 0;
let already = 0;
for (const fp of LEGACY_PAGES) {
  let src = fs.readFileSync(fp, 'utf8');
  const orig = src;
  // Bump any ?v=NNN to current (only for stylesheet/script refs, not for query-strings on links)
  src = src.replace(/(\/(styles|venue)\.css\?v=)\d+/g, `$1${CURRENT}`);
  src = src.replace(/(\/(app|app\.bundle|site-ui|data|search-page|compare|favorites|recent|shortcuts|share|analytics)\.js\?v=)\d+/g, `$1${CURRENT}`);
  // Round 21 - also bump self-hosted font preloads.
  src = src.replace(/(\/fonts\/[a-z0-9-]+\.woff2\?v=)\d+/g, `$1${CURRENT}`);
  // Bump footer version marker — match patterns like "v404", "v405" inside the cyan span
  src = src.replace(/(★ Last updated · [^·]+ · v)\d+/g, `$1${CURRENT}`);
  if (src === orig) { already++; continue; }
  fs.writeFileSync(fp, src);
  bumped++;
}

console.log(`Legacy assets bumped to v${CURRENT}: ${bumped} updated, ${already} already current (of ${LEGACY_PAGES.length} legacy pages)`);
